Patch Set 1:

>  But could you please show asynchronous execution of umount, some cleanup_mnt() stack outside of umount process?
not sure what you mean. this is what can happen on the kernel side:

struct vfsmount *vfs_create_mount(struct fs_context *fc)
...
	if (fc->sb_flags & SB_KERNMOUNT)
		mnt->mnt.mnt_flags = MNT_INTERNAL;


static void mntput_no_expire(struct mount *mnt)
...
	if (likely(!(mnt->mnt.mnt_flags & MNT_INTERNAL))) {
		struct task_struct *task = current;
		if (likely(!(task->flags & PF_KTHREAD))) {
			init_task_work(&mnt->mnt_rcu, __cleanup_mnt);
			if (!task_work_add(task, &mnt->mnt_rcu, true))
				return;
		}
		if (llist_add(&mnt->mnt_llist, &delayed_mntput_list))
			schedule_delayed_work(&delayed_mntput_work, 1);
		return;
	}
	cleanup_mnt(mnt);

i.e. if you don't have MNT_INTERNAL (via SB_KERNMOUNT set), then you risk to hit async umount.
